package io.lievit.wire;

import java.util.ArrayList;
import java.util.List;

import io.lievit.LievitAction;
import io.lievit.LievitComponent;
import io.lievit.LievitProperty;
import io.lievit.LievitRender;
import io.lievit.Wire;

/**
 * {@code accordion}: the server-first WIRE replacement for the {@code <lv-accordion>} Lit island
 * (ADR-0012, Wave 2). A disclosure GROUP: several triggers, each expanding / collapsing its own
 * region; the open set lives here in typed Java, not in client memory, and the server re-renders
 * the template on each toggle (the client morphs the result, preserving focus + scroll). It is the
 * same disclosure idea as {@code collapsible}, composed over many items.
 *
 * <p>WHY server-state: the island held the open set in a Lit reactive {@code Set} and projected
 * each panel through a named {@code <slot>}, which is inert in light DOM, so the panel bodies
 * silently never rendered (the bug class ADR-0012 was written to kill). Here {@link #open} is a
 * {@code @Wire} list round-tripped in the signed snapshot, and the panel bodies are plain
 * server-rendered JTE owned by the template: they cannot fail to project.
 *
 * <p>Convention (blueprint 1.b): state is {@code @Wire public} fields; the toggle is a
 * {@code @LievitAction}; the disclosure a11y (WAI-ARIA APG accordion, the same Radix source the
 * island cited) lives in the template. Because a regular {@code @LievitAction} takes no forwarded
 * arguments (only the magic {@code $set}/{@code $toggle} parse inline args, runtime parity gap), the
 * clicked item is ARMED into {@link #toggleId} via {@code l:click="$set('toggleId','<id>')"} (the
 * canonical Livewire {@code wire:click="$set(...)"} idiom this repo already uses for row-arm in
 * {@code listing-list.jte}); {@link #applyToggle()} then flips that id in the open set on the
 * pre-render hook and clears the arm, so the whole interaction is one click, fully server-side, and
 * idempotent under replay (a cleared arm re-renders to a no-op). The same logic is reachable as the
 * explicit {@link #toggle()} action driven by a render-asserting IT.
 *
 * <p>The item ids + labels are server config ({@code @LievitProperty(locked = true)} so a client
 * cannot inject or rename an item); the panel bodies are OWNED template markup (the server-first
 * equivalent of children, not a {@code <slot>}). Copied in by {@code lievit add accordion}: the
 * adopter OWNS this class AND {@code accordion.jte} (rename the package, change the items, put real
 * panel markup in the owned regions).
 */
@LievitComponent(template = "lievit/accordion")
public class AccordionComponent {

    /**
     * Item ids in render order. Locked: the set of items is server config, a client cannot add,
     * remove, or rename one by editing the snapshot. Paired index-for-index with {@link #labels}.
     */
    @Wire
    @LievitProperty(locked = true)
    public List<String> itemIds = new ArrayList<>();

    /** Trigger labels, index-aligned with {@link #itemIds}. Locked alongside the ids. */
    @Wire
    @LievitProperty(locked = true)
    public List<String> labels = new ArrayList<>();

    /**
     * The currently open item ids. The single piece of disclosure state, held server-side and
     * round-tripped as a plain JSON list. For {@code single} mode it holds at most one id.
     */
    @Wire
    public List<String> open = new ArrayList<>();

    /**
     * {@code "single"} (default): at most one item open at a time; {@code "multiple"}: any number.
     * Locked: the selection mode is server policy, not a client toggle.
     */
    @Wire
    @LievitProperty(locked = true)
    public String mode = "single";

    /**
     * The item a click just armed (via the {@code $set} magic). Consumed + cleared by
     * {@link #applyToggle()} on the next render, so a click reduces to one server round-trip. Empty
     * when no toggle is pending; it never persists across a render.
     */
    @Wire
    public String toggleId = "";

    /**
     * Flips the armed {@link #toggleId} in the open set on every pre-render (the hook the dispatcher
     * runs at mount and before each re-render), then clears the arm. Empty arm = no-op, so a plain
     * re-render (or a snapshot replay carrying a cleared arm) never double-toggles: idempotent.
     */
    @LievitRender
    void applyToggle() {
        if (toggleId.isEmpty() || !itemIds.contains(toggleId)) {
            toggleId = "";
            return;
        }
        flip(toggleId);
        toggleId = "";
    }

    /**
     * Toggles the open/closed state of {@link #toggleId} (the armed item) explicitly. Same effect as
     * the {@code $set}-armed render path: provided so a caller (or a render-asserting test) can drive
     * the transition through the {@code @LievitAction} dispatch with the target supplied as a field
     * update in the same wire call (updates apply before actions, ADR-0001). Clears the arm after.
     */
    @LievitAction
    public void toggle() {
        if (!toggleId.isEmpty() && itemIds.contains(toggleId)) {
            flip(toggleId);
        }
        toggleId = "";
    }

    /** Adds the id to the open set, or removes it if already open; single mode keeps at most one. */
    private void flip(String id) {
        if (open.contains(id)) {
            open.remove(id);
            return;
        }
        if ("single".equals(mode)) {
            open.clear();
        }
        open.add(id);
    }

    /**
     * Whether an item is currently open (read by the template to render aria-expanded + the panel
     * hidden attribute).
     *
     * @param id the item id
     * @return true when the item is in the open set
     */
    public boolean isOpen(String id) {
        return open.contains(id);
    }
}

@import gg.jte.Content
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui alert partial -- an inline message banner whose severity drives colour + role.

  TIER: STATIC presentational -> JTE partial. The former <lv-alert> island held no client
  state; severity-to-colour and severity-to-role are both pure functions of the variant, so
  the server renders the whole thing.

  STRUCTURE (scientific decision rule): WAI-ARIA alert / status pattern. shadcn renders a
  bordered tinted panel keyed on variant; the live-region ROLE is the load-bearing decision
  and is taken from the APG: time-sensitive errors (danger / warning) are assertive
  (role="alert"), informational kinds (info / success) are polite (role="status"), so a
  screen reader interrupts only for the urgent kinds. The tint uses color-mix over the
  severity token so one token drives border + background coherently.

  A11y (WAI-ARIA alert/status): danger|warning => role="alert" (assertive); info|success =>
  role="status" (polite). An optional heading is rendered first; the message is the content slot.

  Params:
    String variant         = "info"   "info" | "success" | "warning" | "danger".
    String heading         = null     optional bold heading rendered above the message.
    gg.jte.Content content            the message body.
    String cssClass        = ""       extra utility classes on the banner.

  Usage:
    @@template.alert(variant = "danger", content = @@`Could not save the listing.`)
    @@template.alert(variant = "success", heading = "Saved", content = @@`Your changes are live.`)
--%>
@param String variant = "info"
@param String heading = null
@param gg.jte.Content content
@param String cssClass = ""

!{var urgent = "danger".equals(variant) || "warning".equals(variant);}
!{var tone = switch (variant) {
    case "success" -> "var(--lv-color-success)";
    case "warning" -> "var(--lv-color-warning)";
    case "danger"  -> "var(--lv-color-danger)";
    default        -> "var(--lv-color-info)";
  };}

<div
  data-slot="alert"
  data-variant="${variant}"
  role="${urgent ? "alert" : "status"}"
  class="block rounded-[var(--lv-radius-md)] border px-[var(--lv-space-4)] py-[var(--lv-space-3)] text-[length:var(--lv-text-sm)] leading-[var(--lv-leading)] text-[var(--lv-color-fg)] ${cssClass}"
  style="font-family:var(--lv-font-sans);border-color:${tone};background:color-mix(in srgb, ${tone} 12%, var(--lv-color-bg));"
>
  @if(heading != null && !heading.isBlank())
    <div data-slot="alert-heading" class="mb-[var(--lv-space-1)] font-[var(--lv-font-semibold)]">${heading}</div>
  @endif
  ${content}
</div>

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 */
package io.lievit.wire;

import io.lievit.LievitAction;
import io.lievit.LievitComponent;
import io.lievit.LievitProperty;
import io.lievit.Wire;

/**
 * {@code alert-dialog}: the server-first WIRE confirm-modal, the {@code role="alertdialog"}
 * specialization of the dialog wire (ADR-0012, Wave 3). It is the interruptive prompt that demands
 * a response (delete this? discard changes?): a title, a description, a destructive-or-primary
 * confirm button and a cancel button, whose open-state lives here in typed Java, not in client
 * memory. The server re-renders the template on {@link #open()} / {@link #confirm()} /
 * {@link #cancel()} and the client morphs the result.
 *
 * <p>WHY a separate component and not the plain {@link DialogComponent}: WAI-ARIA distinguishes
 * {@code role="dialog"} (general) from {@code role="alertdialog"} (an interruptive prompt requiring
 * a response). A confirm is the alertdialog case, so the template sets {@code role="alertdialog"}
 * and the footer is NOT an owned free-form region but two real, named buttons (the destructive
 * action + cancel) wired with {@code l:click}. It builds ON the dialog wire's model (the same
 * server-held open-state + the owned-body finding from Wave 2), specialized for the confirm shape.
 *
 * <p>WHY it composes the dialog wire's STRUCTURE rather than the dialog COMPONENT: a wire template
 * is rendered with ONLY its own {@code @Wire} fields + {@code _component} (JteTemplateAdapter, the
 * Wave 0 finding), so one wire component cannot render another wire component as a nested live
 * instance with a fresh snapshot. The server-first equivalent of "compose the dialog" is therefore
 * to render the dialog's overlay/panel STRUCTURE (the {@code role}, the {@code aria-modal}, the
 * {@code hidden}-when-closed overlay, the title/description header) inside this component's own
 * owned template, specialized to {@code role="alertdialog"} with the confirm footer. The result is
 * a single self-contained wire component with no {@code <lv-dialog>} reference anywhere.
 *
 * <p>Convention (blueprint 1.b): state is {@code @Wire public} fields; the actions are
 * {@code @LievitAction} methods; the modal a11y (WAI-ARIA APG alertdialog: {@code role=alertdialog},
 * {@code aria-modal}, {@code aria-labelledby} -> the title, {@code aria-describedby} -> the
 * description) lives in the template. {@code title} + {@code description} + the button labels +
 * {@code open} round-trip; {@code destructive} is locked so a client cannot downgrade a
 * server-mandated destructive confirm to a benign one (or vice-versa) by editing the snapshot.
 *
 * <p>WHAT happens on confirm is the adopter's: {@link #confirmed} is a wire flag the host page reads
 * after the round-trip (or the adopter overrides {@link #confirm()} to run the destructive operation
 * server-side, with authz, before closing). Either way the server stays the single owner of the
 * outcome; the client only fires the action.
 *
 * <p>Copied in by {@code lievit add alert-dialog}: the adopter OWNS this class (rename it, move the
 * package, do the real work in {@link #confirm()} with server-side authz) AND the
 * {@code alert-dialog.jte} template.
 */
@LievitComponent(template = "lievit/alert-dialog")
public class AlertDialogComponent {

    /** Open state: the single piece of modal state, held server-side. */
    @Wire
    public boolean open = false;

    /** The prompt headline; wired to {@code aria-labelledby}. Round-trips. */
    @Wire
    public String title = "Are you sure?";

    /** The supporting explanation; wired to {@code aria-describedby}. Empty omits it. Round-trips. */
    @Wire
    public String description = "";

    /** The confirm button label. Round-trips. */
    @Wire
    public String actionLabel = "Confirm";

    /** The cancel button label. Round-trips. */
    @Wire
    public String cancelLabel = "Cancel";

    /**
     * When true the confirm button is the destructive (red) affordance + the title carries a
     * triangle-alert icon. Locked so a client cannot flip a server-mandated destructive confirm to a
     * benign one (or vice-versa) by editing the snapshot payload.
     */
    @Wire
    @LievitProperty(locked = true)
    public boolean destructive = false;

    /**
     * Set true once {@link #confirm()} has run, false again on {@link #cancel()} / {@link #open()}.
     * The host page reads this after the round-trip to learn the outcome; an adopter that does the
     * destructive work directly in {@link #confirm()} can ignore it.
     */
    @Wire
    public boolean confirmed = false;

    /** Opens the prompt, clearing any prior outcome so a re-open starts unanswered. */
    @LievitAction
    public void open() {
        confirmed = false;
        open = true;
    }

    /**
     * Confirms the prompt: records the outcome and closes. The adopter overrides this to run the
     * destructive operation server-side (with authz) before it closes; doing it here keeps the
     * server the single owner of the outcome.
     */
    @LievitAction
    public void confirm() {
        confirmed = true;
        open = false;
    }

    /** Cancels the prompt: clears the outcome and closes. */
    @LievitAction
    public void cancel() {
        confirmed = false;
        open = false;
    }
}

@import gg.jte.Content
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui badge partial -- a small status pill, the gestionale status indicator.

  TIER: STATIC presentational -> JTE partial (ADR-0012 server-first pivot). The former
  <lv-badge> island held no client state; variant-to-colour is a pure function of the
  variant, so the server renders the whole pill. The Lit island is gone; this is the to-be.

  STRUCTURE (scientific decision rule): shadcn's Badge is a single styled <span> keyed on a
  variant. The status variants map to the status tokens (success / warning / danger / info)
  plus a muted neutral default; each variant drives a fill + foreground token pair, exactly
  the mapping the dropped island shipped, so a retheme retints every pill from the tokens.
  The label is plain text (the common kit call: @@template.badge(variant=.., label="..")),
  with an optional Content slot for rich children that takes precedence when supplied (the
  same content-over-scalar precedence kbd.jte uses).

  CSS COMPAT: the pill keeps the `lv-badge lv-badge--<variant>` class names the island used,
  so any stylesheet that targeted them still applies; the partial is self-styling via inline
  token-driven CSS (no external rule needed), consistent with the other w1a partials.

  A11y: a status pill is decorative text; it carries no role (it is not a live region -- the
  surrounding context, e.g. a table cell or an alert, owns any announcement). Colour is never
  the only signal: the label text always states the status.

  Params:
    String variant         = "neutral"  "neutral" | "success" | "warning" | "danger" | "info".
    String label           = null       the pill text (used when no content slot is supplied).
    gg.jte.Content content              optional rich children; takes precedence over label.
    String cssClass        = ""         extra utility classes on the pill.

  Usage:
    @@template.badge(variant = "success", label = "Attivo")
    @@template.badge(variant = "danger", content = @@`<strong>Scaduto</strong>`)
--%>
@param String variant = "neutral"
@param String label = null
@param gg.jte.Content content = null
@param String cssClass = ""

!{var bg = switch (variant) {
    case "success" -> "var(--lv-color-success)";
    case "warning" -> "var(--lv-color-warning)";
    case "danger"  -> "var(--lv-color-danger)";
    case "info"    -> "var(--lv-color-info)";
    default        -> "var(--lv-color-surface)";
  };}
!{var fg = switch (variant) {
    case "success" -> "var(--lv-color-success-fg)";
    case "warning" -> "var(--lv-color-warning-fg)";
    case "danger"  -> "var(--lv-color-danger-fg)";
    case "info"    -> "var(--lv-color-info-fg)";
    default        -> "var(--lv-color-muted)";
  };}

<span
  data-slot="badge"
  data-variant="${variant}"
  class="lv-badge lv-badge--${variant} inline-flex items-center rounded-[var(--lv-radius-sm)] px-[var(--lv-space-2)] py-[var(--lv-space-1)] text-[length:var(--lv-text-sm)] font-[var(--lv-font-medium)] leading-none ${cssClass}"
  style="font-family:var(--lv-font-sans);background:${bg};color:${fg};"
>@if(content != null)${content}@else${label}@endif</span>

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 */
import { LitElement, html } from "lit";
import { customElement, property, state } from "lit/decorators.js";
import { unsafeSVG } from "lit/directives/unsafe-svg.js";
import { adoptLightStyles } from "../light-dom/light-dom.js";
import { iconBody } from "../../icons/icon-bodies.js";

/**
 * `<lv-calendar>`: a standalone, inline month-grid date picker primitive.
 *
 * This is the bare calendar surface (no input, no floating panel): the month grid the
 * date-picker conceptually contains, exposed on its own so it can be embedded anywhere
 * (popover, sidebar, dialog, scheduling UI). It follows the WAI-ARIA APG grid pattern for
 * a date picker:
 * - `role="grid"` on the table, `role="gridcell"` on each day cell, `role="columnheader"`
 *   on the weekday headers.
 * - The selected cell carries `aria-selected="true"`; the today cell carries
 *   `aria-current="date"`.
 * - Roving tabindex: exactly one day is in the tab order at a time; arrow keys move focus,
 *   Home/End jump to the week edges, PageUp/PageDown change month, Enter/Space select.
 * - Locale-aware first-day-of-week (`weekStart`, default Monday per ISO).
 *
 * Data down, events up: `value` is the selected ISO date (single mode) or the comma range
 * `"start,end"` (range mode). Emits `lv-change` with the new value on selection.
 * Disabled days (via `min`, `max`, or the `isDisabled` predicate) cannot be focused or
 * selected. Light-DOM rendered; the date-picker keeps its own internal grid, this is the
 * reusable primitive the rest of the library composes with.
 */
@customElement("lv-calendar")
export class LvCalendar extends LitElement {
  /**
   * Selected value. Single mode: an ISO date `YYYY-MM-DD` or empty. Range mode: `"start,end"`
   * (either side may be empty while the range is being built).
   */
  @property() value = "";

  /** `"single"` selects one date; `"range"` selects a start/end pair. */
  @property() mode: "single" | "range" = "single";

  /** Earliest selectable ISO date (inclusive), or empty for no lower bound. */
  @property() min = "";

  /** Latest selectable ISO date (inclusive), or empty for no upper bound. */
  @property() max = "";

  /** Disables the whole calendar. */
  @property({ type: Boolean }) disabled = false;

  /** First day of the week: 0 = Sunday, 1 = Monday (default, ISO). */
  @property({ type: Number }) weekStart = 1;

  /** BCP-47 locale for month + weekday names and day labels (default = host locale). */
  @property() locale = "";

  /**
   * Optional predicate that disables individual days. Set as a property (not an attribute):
   * `el.isDisabled = (iso) => isWeekend(iso)`.
   */
  @property({ attribute: false }) isDisabled: ((iso: string) => boolean) | null = null;

  @state() private viewYear = 0;
  @state() private viewMonth = 0; // 0-11
  @state() private focusedDate = "";

  private initialized = false;

  createRenderRoot(): this {
    adoptLightStyles("lv-calendar", LvCalendar.css);
    return this;
  }

  static readonly css = `
    .lv-calendar {
      display: inline-block;
      font-family: var(--lv-font-sans);
      color: var(--lv-color-fg);
      background: var(--lv-color-bg);
      padding: var(--lv-space-3);
      border-radius: var(--lv-radius-md);
    }
    .lv-calendar__header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: var(--lv-space-2);
    }
    .lv-calendar__nav {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: 2rem;
      height: 2rem;
      background: transparent;
      border: 1px solid var(--lv-color-border);
      border-radius: var(--lv-radius-sm);
      cursor: pointer;
      color: var(--lv-color-fg);
    }
    .lv-calendar__nav:hover:not([disabled]) { background: var(--lv-color-surface); }
    .lv-calendar__nav:focus-visible { outline: none; box-shadow: var(--lv-ring); }
    .lv-calendar__nav[disabled] { opacity: 0.4; cursor: not-allowed; }
    .lv-calendar__nav svg { width: 1rem; height: 1rem; }
    .lv-calendar__label {
      font-size: var(--lv-text-sm);
      font-weight: var(--lv-font-semibold);
      color: var(--lv-color-fg);
    }
    .lv-calendar__grid { border-collapse: collapse; }
    .lv-calendar__day-header {
      font-size: var(--lv-text-xs);
      color: var(--lv-color-muted-fg);
      font-weight: var(--lv-font-medium);
      padding: var(--lv-space-1);
      text-align: center;
      width: 2.25rem;
    }
    .lv-calendar__cell { padding: 1px; text-align: center; }
    .lv-calendar__day {
      width: 2.25rem;
      height: 2.25rem;
      border: 0;
      border-radius: var(--lv-radius-sm);
      background: transparent;
      font-family: var(--lv-font-sans);
      font-size: var(--lv-text-sm);
      color: var(--lv-color-fg);
      cursor: pointer;
      display: inline-flex;
      align-items: center;
      justify-content: center;
    }
    .lv-calendar__day:focus-visible { outline: none; box-shadow: var(--lv-ring); }
    .lv-calendar__day:hover:not([disabled]) { background: var(--lv-color-surface); }
    .lv-calendar__day--today {
      font-weight: var(--lv-font-semibold);
      border: 1px solid var(--lv-color-border);
    }
    .lv-calendar__day--selected {
      background: var(--lv-color-primary);
      color: var(--lv-color-primary-fg);
      font-weight: var(--lv-font-semibold);
    }
    .lv-calendar__day--selected:hover:not([disabled]) { background: var(--lv-color-primary); }
    .lv-calendar__day--in-range {
      background: var(--lv-color-accent);
      color: var(--lv-color-accent-fg);
      border-radius: 0;
    }
    .lv-calendar__day--range-start { border-top-right-radius: 0; border-bottom-right-radius: 0; }
    .lv-calendar__day--range-end { border-top-left-radius: 0; border-bottom-left-radius: 0; }
    .lv-calendar__day[disabled] { opacity: 0.4; cursor: not-allowed; }
  `;

  private get effectiveLocale(): string | undefined {
    return this.locale || undefined;
  }

  private get todayISO(): string {
    return LvCalendar.toISO(new Date());
  }

  private static toISO(d: Date): string {
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(
      d.getDate()
    ).padStart(2, "0")}`;
  }

  private static parseISO(iso: string): Date | null {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(iso)) return null;
    const d = new Date(iso + "T00:00:00");
    return isNaN(d.getTime()) ? null : d;
  }

  /** The selected dates parsed from `value`: [] / [single] / [start, end] (end may be ""). */
  private get selection(): string[] {
    if (this.mode === "range") {
      return this.value
        .split(",")
        .map((s) => s.trim())
        .filter(Boolean);
    }
    return this.value ? [this.value] : [];
  }

  willUpdate(changed: Map<string, unknown>) {
    if (!this.initialized) {
      this.initialized = true;
      const anchor = LvCalendar.parseISO(this.selection[0] ?? "") ?? new Date();
      this.viewYear = anchor.getFullYear();
      this.viewMonth = anchor.getMonth();
      this.focusedDate = this.selection[0] || this.todayISO;
    } else if (changed.has("value") && this.value) {
      // Keep the focused day in sync when the value is driven from outside.
      const first = this.selection[0];
      if (first) this.focusedDate = first;
    }
  }

  private isOutOfBounds(iso: string): boolean {
    if (this.min && iso < this.min) return true;
    if (this.max && iso > this.max) return true;
    return false;
  }

  private dayDisabled(iso: string): boolean {
    if (this.disabled) return true;
    if (this.isOutOfBounds(iso)) return true;
    return this.isDisabled ? this.isDisabled(iso) : false;
  }

  private prevMonth = () => {
    if (this.viewMonth === 0) {
      this.viewMonth = 11;
      this.viewYear--;
    } else {
      this.viewMonth--;
    }
  };

  private nextMonth = () => {
    if (this.viewMonth === 11) {
      this.viewMonth = 0;
      this.viewYear++;
    } else {
      this.viewMonth++;
    }
  };

  private select(iso: string) {
    if (this.dayDisabled(iso)) return;

    if (this.mode === "single") {
      this.value = iso;
    } else {
      const sel = this.selection;
      if (sel.length === 0 || sel.length === 2) {
        // Start a fresh range.
        this.value = iso;
      } else {
        // Close the range, ordering ascending.
        const [start] = sel;
        this.value = iso < start ? `${iso},${start}` : `${start},${iso}`;
      }
    }
    this.focusedDate = iso;
    this.dispatchEvent(
      new CustomEvent("lv-change", { detail: this.value, bubbles: true, composed: true })
    );
  }

  private focusDay() {
    this.querySelector<HTMLElement>(`[data-date="${this.focusedDate}"]`)?.focus();
  }

  private moveFocus(next: Date) {
    this.focusedDate = LvCalendar.toISO(next);
    this.viewYear = next.getFullYear();
    this.viewMonth = next.getMonth();
    this.updateComplete.then(() => this.focusDay());
  }

  private onGridKeyDown = (e: KeyboardEvent) => {
    const base = LvCalendar.parseISO(this.focusedDate);
    if (!base) return;
    const d = new Date(base);

    switch (e.key) {
      case "ArrowRight":
        e.preventDefault();
        d.setDate(d.getDate() + 1);
        this.moveFocus(d);
        break;
      case "ArrowLeft":
        e.preventDefault();
        d.setDate(d.getDate() - 1);
        this.moveFocus(d);
        break;
      case "ArrowDown":
        e.preventDefault();
        d.setDate(d.getDate() + 7);
        this.moveFocus(d);
        break;
      case "ArrowUp":
        e.preventDefault();
        d.setDate(d.getDate() - 7);
        this.moveFocus(d);
        break;
      case "Home":
        e.preventDefault();
        d.setDate(d.getDate() - this.dowFromMonday(d));
        this.moveFocus(d);
        break;
      case "End":
        e.preventDefault();
        d.setDate(d.getDate() + (6 - this.dowFromMonday(d)));
        this.moveFocus(d);
        break;
      case "PageUp":
        e.preventDefault();
        d.setMonth(d.getMonth() - 1);
        this.moveFocus(d);
        break;
      case "PageDown":
        e.preventDefault();
        d.setMonth(d.getMonth() + 1);
        this.moveFocus(d);
        break;
      case "Enter":
      case " ":
        e.preventDefault();
        this.select(this.focusedDate);
        break;
    }
  };

  /** Offset of `d` from the configured week-start (0..6), so Home/End land on the visual row. */
  private dowFromMonday(d: Date): number {
    return (d.getDay() - this.weekStart + 7) % 7;
  }

  private weekdayHeaders(): { label: string; full: string }[] {
    const fmtShort = new Intl.DateTimeFormat(this.effectiveLocale, { weekday: "short" });
    const fmtLong = new Intl.DateTimeFormat(this.effectiveLocale, { weekday: "long" });
    // 2024-01-07 is a Sunday; build the 7 weekday labels starting at weekStart.
    const out: { label: string; full: string }[] = [];
    for (let i = 0; i < 7; i++) {
      const day = new Date(2024, 0, 7 + ((this.weekStart + i) % 7));
      out.push({ label: fmtShort.format(day), full: fmtLong.format(day) });
    }
    return out;
  }

  private buildWeeks(): (string | null)[][] {
    const first = new Date(this.viewYear, this.viewMonth, 1);
    const lastDay = new Date(this.viewYear, this.viewMonth + 1, 0).getDate();
    const lead = (first.getDay() - this.weekStart + 7) % 7;

    const cells: (string | null)[] = [];
    for (let i = 0; i < lead; i++) cells.push(null);
    for (let day = 1; day <= lastDay; day++) {
      cells.push(
        `${this.viewYear}-${String(this.viewMonth + 1).padStart(2, "0")}-${String(
          day
        ).padStart(2, "0")}`
      );
    }
    while (cells.length % 7 !== 0) cells.push(null);

    const weeks: (string | null)[][] = [];
    for (let i = 0; i < cells.length; i += 7) weeks.push(cells.slice(i, i + 7));
    return weeks;
  }

  private inRange(iso: string): boolean {
    if (this.mode !== "range") return false;
    const sel = this.selection;
    if (sel.length < 2) return false;
    return iso > sel[0] && iso < sel[1];
  }

  render() {
    const monthLabel = new Intl.DateTimeFormat(this.effectiveLocale, {
      month: "long",
      year: "numeric",
    }).format(new Date(this.viewYear, this.viewMonth, 1));
    const dayFmt = new Intl.DateTimeFormat(this.effectiveLocale, {
      year: "numeric",
      month: "long",
      day: "numeric",
    });
    const headers = this.weekdayHeaders();
    const weeks = this.buildWeeks();
    const today = this.todayISO;
    const sel = this.selection;
    const prevDisabled = this.disabled;
    const nextDisabled = this.disabled;

    return html`
      <div class="lv-calendar" role="group" aria-label=${monthLabel}>
        <div class="lv-calendar__header">
          <button
            class="lv-calendar__nav lv-calendar__nav--prev"
            type="button"
            aria-label="Previous month"
            ?disabled=${prevDisabled}
            @click=${this.prevMonth}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"
              stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"
            >${unsafeSVG(iconBody("chevron-left"))}</svg>
          </button>
          <span class="lv-calendar__label" aria-live="polite">${monthLabel}</span>
          <button
            class="lv-calendar__nav lv-calendar__nav--next"
            type="button"
            aria-label="Next month"
            ?disabled=${nextDisabled}
            @click=${this.nextMonth}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"
              stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"
            >${unsafeSVG(iconBody("chevron-right"))}</svg>
          </button>
        </div>

        <table class="lv-calendar__grid" role="grid" aria-label=${monthLabel}
          @keydown=${this.onGridKeyDown}>
          <thead>
            <tr>
              ${headers.map(
                (h) => html`<th
                  class="lv-calendar__day-header"
                  role="columnheader"
                  scope="col"
                  abbr=${h.full}
                >
                  <span aria-hidden="true">${h.label}</span>
                </th>`
              )}
            </tr>
          </thead>
          <tbody>
            ${weeks.map(
              (week) => html`<tr>
                ${week.map((iso) =>
                  iso
                    ? html`<td class="lv-calendar__cell" role="gridcell"
                        aria-selected=${sel.includes(iso) ? "true" : "false"}>
                        <button
                          class="lv-calendar__day
                            ${sel.includes(iso) ? "lv-calendar__day--selected" : ""}
                            ${iso === sel[0] && sel.length === 2
                              ? "lv-calendar__day--range-start"
                              : ""}
                            ${iso === sel[1] ? "lv-calendar__day--range-end" : ""}
                            ${this.inRange(iso) ? "lv-calendar__day--in-range" : ""}
                            ${iso === today && !sel.includes(iso)
                              ? "lv-calendar__day--today"
                              : ""}"
                          type="button"
                          data-date=${iso}
                          tabindex=${iso === this.focusedDate ? "0" : "-1"}
                          aria-current=${iso === today ? "date" : "false"}
                          aria-label=${dayFmt.format(LvCalendar.parseISO(iso)!)}
                          ?disabled=${this.dayDisabled(iso)}
                          @click=${() => this.select(iso)}
                        >${iso.slice(8).replace(/^0/, "")}</button>
                      </td>`
                    : html`<td class="lv-calendar__cell" role="gridcell"></td>`
                )}
              </tr>`
            )}
          </tbody>
        </table>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    "lv-calendar": LvCalendar;
  }
}

